func New(config ...Config) fiber.Handler {

	cfg := configDefault(config...)

	return func(c fiber.Ctx) (err error) {

		if cfg.Next != nil && cfg.Next(c) {
			return c.Next()
		}

		defer func() {
			if r := recover(); r != nil {
				if cfg.EnableStackTrace {
					cfg.StackTraceHandler(c, r)
				}

				var ok bool
				if err, ok = r.(error); !ok {

					err = fmt.Errorf("%v", r)
				}
			}
		}()

		return c.Next()
	}
}
